function solve(nums) {
    const n = nums.length;
    if (n === 0) return 0;

    // Precompute smallest prime factors (SPF) up to 1e6
    const maxNum = 1000000;
    const spf = new Array(maxNum + 1).fill(0);
    for (let i = 2; i <= maxNum; i++) {
        if (spf[i] === 0) {
            spf[i] = i;
            for (let j = i * 2; j <= maxNum; j += i) {
                if (spf[j] === 0) {
                    spf[j] = i;
                }
            }
        }
    }

    // Build map from primes to indices divisible by them
    const primeToIndices = new Map();
    for (let i = 0; i < n; i++) {
        const x = nums[i];
        if (x === 1) continue;
        let temp = x;
        const primes = new Set();
        while (temp > 1) {
            const p = spf[temp];
            primes.add(p);
            while (temp % p === 0) {
                temp /= p;
            }
        }
        for (const p of primes) {
            if (!primeToIndices.has(p)) {
                primeToIndices.set(p, []);
            }
            primeToIndices.get(p).push(i);
        }
    }

    // BFS setup
    const visited = new Array(n).fill(false);
    const queue = [[0, 0]];
    visited[0] = true

